// Build {sequence_id -> name} so steps can inherit region/pillar from their parent sequence.
const map = {};
for (const item of $input.all()) {
  const body = item.json || {};
  const list = Array.isArray(body.data) ? body.data : (Array.isArray(body) ? body : [body]);
  for (const s of list) {
    if (s && s.id != null) map[String(s.id)] = (s.attributes && s.attributes.name) || '';
  }
}
return [{ json: { map } }];

// Outreach /sequenceSteps -> fact_outreach_step_daily (SNAPSHOT per run).
// Per-step counters are LIFETIME totals -> activity_date = run date (upserts in place).
// region/pillar are inherited from the parent sequence's name (same rules as the sequence feed).
const seqMap = ($('Build Sequence Map').first().json || {}).map || {};

const REGIONS = ['UKI', 'BeLux', 'NL', 'UNASSIGNED'];
const PILLARS = ['Secure AI', 'Secure Data', 'Secure Endpoints', 'Secure Identity', 'Secure Operations'];
function regionFromName(nm) {
  const n = String(nm || '').toLowerCase();
  if (/belux/.test(n)) return 'BeLux';
  if (/(^|[^a-z])nl([^a-z]|$)|netherlands|gemeente/.test(n)) return 'NL';
  if (/uk&i|uk & i|\buki\b|united kingdom|\buk\b|ireland|dublin/.test(n)) return 'UKI';
  return 'UNASSIGNED';
}
function pillarFromName(nm) {
  const n = String(nm || '').toLowerCase();
  if (/secure ai|copilot|(^|[^a-z])ai([^a-z]|$)|agents? 365/.test(n)) return 'Secure AI';
  if (/secure data|data security|data is an asset/.test(n)) return 'Secure Data';
  if (/secure endpoint|endpoint|\buem\b|device/.test(n)) return 'Secure Endpoints';
  if (/secure identity|identity/.test(n)) return 'Secure Identity';
  if (/secure operations|secops|threat protection|frontline operations/.test(n)) return 'Secure Operations';
  return null;
}
function num(v) { const n = Number(v); return isNaN(n) ? 0 : n; }

const today = new Date().toISOString().slice(0, 10);
const out = [];
for (const item of $input.all()) {
  const body = item.json || {};
  const list = Array.isArray(body.data) ? body.data : (Array.isArray(body) ? body : [body]);
  for (const st of list) {
    if (!st || st.id == null) continue;
    const a = st.attributes || {};
    const rel = st.relationships || {};
    const seqId = rel.sequence && rel.sequence.data && rel.sequence.data.id;
    if (seqId == null) continue;
    const name = seqMap[String(seqId)] || '';
    let region = regionFromName(name);
    let pillar = pillarFromName(name);
    if (REGIONS.indexOf(region) < 0) region = 'UNASSIGNED';
    if (pillar && PILLARS.indexOf(pillar) < 0) pillar = null;
    out.push({ json: {
      activity_date: today,
      sequence_id: String(seqId),
      step_id: String(st.id),
      region_code: region,
      pillar_name: pillar,
      step_order: a.order != null ? Number(a.order) : null,
      step_type: a.stepType || null,
      delivered: num(a.deliverCount),
      opens: num(a.openCount),
      clicks: num(a.clickCount),
      replies: num(a.replyCount),
      bounces: num(a.bounceCount),
      opt_outs: num(a.optOutCount)
    } });
  }
}
if (out.length === 0) {
  throw new Error('Outreach steps: nothing returned - check sequenceSteps.read scope on the credential.');
}
return out;
